const item = $input.item.json;

// ─── SUBJECT MARKS ───────────────────────────────────────────

const subjects = {
  'Math':    parseInt(item['Math']    || 0),
  'Science': parseInt(item['Science'] || 0),
  'English': parseInt(item['English'] || 0),
  'Hindi':   parseInt(item['Hindi']   || 0),
  'SST':     parseInt(item['SST']     || 0)
};

const maxPerSubject = parseInt(item['Max_Per_Subject'] || 100);
const totalSubjects = Object.keys(subjects).length;
const maxMarks      = maxPerSubject * totalSubjects;
const totalMarks    = Object.values(subjects).reduce((a, b) => a + b, 0);
const percentage    = ((totalMarks / maxMarks) * 100).toFixed(1);

// ─── GRADE & COLOR ───────────────────────────────────────────
let grade, gradeColor, gradeBg, remark;

if (percentage >= 90) {
  grade     = 'A+';
  gradeColor = '#1b5e20';
  gradeBg   = '#e8f5e9';
  remark    = 'Outstanding performance! Truly exceptional dedication and hard work this term.';
} else if (percentage >= 75) {
  grade     = 'A';
  gradeColor = '#1565c0';
  gradeBg   = '#e3f2fd';
  remark    = 'Excellent work. A consistent and hardworking student. Keep it up!';
} else if (percentage >= 60) {
  grade     = 'B';
  gradeColor = '#e65100';
  gradeBg   = '#fff3e0';
  remark    = 'Good performance. Focused attention on weaker subjects will bring further improvement.';
} else if (percentage >= 45) {
  grade     = 'C';
  gradeColor = '#6a1b9a';
  gradeBg   = '#f3e5f5';
  remark    = 'Satisfactory. Regular study habits and parental support will help improve results.';
} else {
  grade     = 'D';
  gradeColor = '#b71c1c';
  gradeBg   = '#ffebee';
  remark    = 'Needs significant improvement. Please schedule a meeting with the class teacher at the earliest.';
}

// ─── SUBJECT RESULTS ─────────────────────────────────────────
const passMarkPct = 0.33; // 33% to pass each subject
const subjectResults = Object.entries(subjects).map(([name, marks]) => ({
  name,
  marks,
  max: maxPerSubject,
  pct: ((marks / maxPerSubject) * 100).toFixed(0),
  pass: marks >= (maxPerSubject * passMarkPct),
  passColor: marks >= (maxPerSubject * passMarkPct) ? '#2e7d32' : '#c62828',
  passBg:    marks >= (maxPerSubject * passMarkPct) ? '#e8f5e9' : '#ffebee',
  passLabel: marks >= (maxPerSubject * passMarkPct) ? 'Pass' : 'Fail'
}));

// ─── ATTENDANCE STYLING ──────────────────────────────────────
const attendance = parseFloat(item['Attendance'] || 0);
const attendanceColor = attendance >= 85 ? '#1b5e20' : attendance >= 75 ? '#e65100' : '#b71c1c';

return {
  ...item,
  calc_subjects:        JSON.stringify(subjectResults),
  calc_totalMarks:      totalMarks,
  calc_maxMarks:        maxMarks,
  calc_percentage:      parseFloat(percentage),
  calc_grade:           grade,
  calc_gradeColor:      gradeColor,
  calc_gradeBg:         gradeBg,
  calc_remark:          remark,
  calc_attendance:      attendance,
  calc_attendanceColor: attendanceColor,
  calc_term:            item['Term'] || 'Term 2',
  calc_year:            item['Academic_Year'] || '2024-25'
};

const d = $input.item.json;
const subjects = JSON.parse(d.calc_subjects);

// ─── BUILD SUBJECT TABLE ROWS ─────────────────────────────────
const tableRows = subjects.map(s => `
  <tr>
    <td style="padding:10px 16px;border-bottom:1px solid #f0f0f0;font-weight:600;color:#333;font-size:13px">${s.name}</td>
    <td style="padding:10px 16px;border-bottom:1px solid #f0f0f0;text-align:center;font-size:13px;color:#555">${s.marks} / ${s.max}</td>
    <td style="padding:10px 16px;border-bottom:1px solid #f0f0f0;text-align:center;font-size:13px;font-weight:700;color:#333">${s.pct}%</td>
    <td style="padding:10px 16px;border-bottom:1px solid #f0f0f0;text-align:center">
      <span style="background:${s.passBg};color:${s.passColor};padding:4px 14px;border-radius:20px;font-size:11px;font-weight:800;letter-spacing:0.5px">${s.passLabel}</span>
    </td>
  </tr>`).join('');

// ─── FULL HTML REPORT CARD ────────────────────────────────────
const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif; background: #fff; color: #333; -webkit-print-color-adjust: exact; }
  .page { width: 210mm; min-height: 297mm; padding: 16mm 18mm; }

  /* HEADER */
  .header { text-align: center; padding-bottom: 16px; margin-bottom: 20px; border-bottom: 3px solid ${d.calc_gradeColor}; }
  .school-emblem { width: 64px; height: 64px; border-radius: 50%; background: ${d.calc_gradeColor}; display: inline-flex; align-items: center; justify-content: center; font-size: 28px; margin-bottom: 10px; }
  .school-name { font-size: 22px; font-weight: 900; color: ${d.calc_gradeColor}; letter-spacing: 0.5px; text-transform: uppercase; }
  .school-sub { font-size: 12px; color: #888; margin-top: 3px; }
  .report-badge { display: inline-block; margin-top: 12px; background: ${d.calc_gradeColor}; color: #fff; padding: 6px 24px; border-radius: 4px; font-size: 12px; font-weight: 800; letter-spacing: 2px; text-transform: uppercase; }
  .report-term { font-size: 12px; color: #888; margin-top: 6px; }

  /* STUDENT INFO */
  .student-card { display: grid; grid-template-columns: 1fr 1fr; gap: 0; border: 1.5px solid ${d.calc_gradeColor}40; border-radius: 10px; overflow: hidden; margin: 18px 0; }
  .info-cell { padding: 12px 16px; border-right: 1px solid #f0f0f0; border-bottom: 1px solid #f0f0f0; }
  .info-cell:nth-child(2n) { border-right: none; }
  .info-cell:nth-last-child(-n+2) { border-bottom: none; }
  .info-lbl { font-size: 10px; color: #999; font-weight: 700; text-transform: uppercase; letter-spacing: 0.8px; }
  .info-val { font-size: 14px; font-weight: 800; color: #222; margin-top: 3px; }

  /* TABLE */
  .section-lbl { font-size: 11px; font-weight: 800; color: ${d.calc_gradeColor}; text-transform: uppercase; letter-spacing: 1.5px; margin: 18px 0 10px; }
  table { width: 100%; border-collapse: collapse; border-radius: 8px; overflow: hidden; border: 1px solid #e8e8e8; }
  thead { background: ${d.calc_gradeColor}; }
  th { padding: 11px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #fff; letter-spacing: 0.8px; text-transform: uppercase; }
  th:not(:first-child) { text-align: center; }
  .total-row { background: ${d.calc_gradeBg}; }
  .total-row td { font-weight: 800; font-size: 13px; padding: 12px 16px; }
  .total-row td:not(:first-child) { text-align: center; }

  /* GRADE SUMMARY */
  .grade-strip { background: linear-gradient(135deg, ${d.calc_gradeColor}, ${d.calc_gradeColor}bb); color: #fff; border-radius: 10px; padding: 16px 20px; margin: 18px 0; display: flex; align-items: center; gap: 20px; }
  .grade-letter { font-size: 56px; font-weight: 900; line-height: 1; opacity: 0.95; min-width: 60px; }
  .grade-details .grade-pct { font-size: 26px; font-weight: 800; }
  .grade-details .grade-sub { font-size: 12px; opacity: 0.85; margin-top: 2px; }

  /* STATS ROW */
  .stats-row { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 10px; margin: 14px 0; }
  .stat-card { background: #fafafa; border: 1px solid #eee; border-radius: 8px; padding: 12px 14px; text-align: center; }
  .stat-val { font-size: 20px; font-weight: 900; color: ${d.calc_gradeColor}; }
  .stat-lbl { font-size: 10px; color: #999; margin-top: 3px; text-transform: uppercase; font-weight: 700; letter-spacing: 0.5px; }

  /* REMARK */
  .remark-box { background: #fffde7; border-left: 4px solid #ffc107; padding: 12px 16px; border-radius: 0 8px 8px 0; margin: 14px 0; }
  .remark-title { font-size: 10px; color: #888; font-weight: 800; text-transform: uppercase; letter-spacing: 0.8px; margin-bottom: 5px; }
  .remark-text { font-size: 13px; color: #444; line-height: 1.65; font-style: italic; }

  /* SIGNATURES */
  .signatures { margin-top: 40px; display: grid; grid-template-columns: 1fr 1fr 1fr; text-align: center; }
  .sig-block { border-top: 1px solid #ccc; padding-top: 8px; margin: 0 12px; font-size: 11px; color: #777; }

  /* FOOTER */
  .watermark { text-align: center; margin-top: 20px; font-size: 10px; color: #bbb; padding-top: 12px; border-top: 1px solid #f0f0f0; }
</style>
</head>
<body>
<div class="page">

  <!-- SCHOOL HEADER -->
  <div class="header">
    <div class="school-emblem">🎓</div>
    <div class="school-name">YOUR SCHOOL NAME</div>
    <div class="school-sub">Affiliated to CBSE, New Delhi &nbsp;|&nbsp; School Code: 00000</div>
    <div class="school-sub">123, School Road, Your City &nbsp;|&nbsp; Tel: +91 XXXXXXXXXX &nbsp;|&nbsp; user@example.com</div>
    <div class="report-badge">Student Progress Report</div>
    <div class="report-term">${d.calc_term} &nbsp;&bull;&nbsp; Academic Year ${d.calc_year}</div>
  </div>

  <!-- STUDENT INFO GRID -->
  <div class="student-card">
    <div class="info-cell">
      <div class="info-lbl">Student Name</div>
      <div class="info-val">${d['Student_Name'] || ''}</div>
    </div>
    <div class="info-cell">
      <div class="info-lbl">Class &amp; Section</div>
      <div class="info-val">Class ${d['Class'] || ''} &mdash; Section ${d['Section'] || ''}</div>
    </div>
    <div class="info-cell">
      <div class="info-lbl">Roll Number</div>
      <div class="info-val">${d['Roll_No'] || ''}</div>
    </div>
    <div class="info-cell">
      <div class="info-lbl">Examination</div>
      <div class="info-val">${d.calc_term}, ${d.calc_year}</div>
    </div>
  </div>

  <!-- MARKS TABLE -->
  <div class="section-lbl">📊 Subject-wise Performance</div>
  <table>
    <thead>
      <tr>
        <th>Subject</th>
        <th>Marks Obtained</th>
        <th>Percentage</th>
        <th>Result</th>
      </tr>
    </thead>
    <tbody>
      ${tableRows}
      <tr class="total-row">
        <td>Total / Grand Total</td>
        <td style="text-align:center">${d.calc_totalMarks} / ${d.calc_maxMarks}</td>
        <td style="text-align:center">${d.calc_percentage}%</td>
        <td style="text-align:center">
          <span style="background:${d.calc_gradeBg};color:${d.calc_gradeColor};padding:4px 14px;border-radius:20px;font-size:11px;font-weight:800">Grade ${d.calc_grade}</span>
        </td>
      </tr>
    </tbody>
  </table>

  <!-- GRADE CARD -->
  <div class="grade-strip">
    <div class="grade-letter">${d.calc_grade}</div>
    <div class="grade-details">
      <div class="grade-pct">${d.calc_percentage}% &mdash; ${d.calc_totalMarks} / ${d.calc_maxMarks}</div>
      <div class="grade-sub">Overall Performance &bull; ${d.calc_term} ${d.calc_year}</div>
    </div>
  </div>

  <!-- STATS -->
  <div class="stats-row">
    <div class="stat-card">
      <div class="stat-val" style="color:${d.calc_gradeColor}">${d.calc_grade}</div>
      <div class="stat-lbl">Grade</div>
    </div>
    <div class="stat-card">
      <div class="stat-val">${d.calc_percentage}%</div>
      <div class="stat-lbl">Overall %</div>
    </div>
    <div class="stat-card">
      <div class="stat-val" style="color:${d.calc_attendanceColor}">${d.calc_attendance}%</div>
      <div class="stat-lbl">Attendance</div>
    </div>
  </div>

  <!-- REMARK -->
  <div class="remark-box">
    <div class="remark-title">📝 Class Teacher's Remark</div>
    <div class="remark-text">${d.calc_remark}</div>
  </div>

  <!-- SIGNATURES -->
  <div class="signatures">
    <div class="sig-block">Class Teacher</div>
    <div class="sig-block">Exam Controller</div>
    <div class="sig-block">Principal</div>
  </div>

  <!-- WATERMARK -->
  <div class="watermark">
    This is a system-generated report &bull; Generated on ${new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })} &bull; For queries contact the school office
  </div>

</div>
</body>
</html>`;

// Convert HTML string to binary so Gotenberg can receive it
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(html, 'utf8'),
  'report_card.html',
  'text/html'
);

return {
  json: {
    ...$input.item.json,
    reportHtml: html // This sends the full HTML as a text property
  }
};
